const triggerData = $input.first().json;
let parsedData = {};

if (triggerData.query) {
  try {
    const parsed = JSON.parse(triggerData.query);
    parsedData = Array.isArray(parsed) ? parsed[0] : parsed;
  } catch (e) {
    parsedData = triggerData;
  }
} else {
  parsedData = triggerData;
}

// Validate section_type
const validSections = [
  'approach', 'strengths', 'development', 'values',
  'top_career_1', 'top_career_2', 'top_career_3',
  'runner_ups', 'outside_box', 'dream_jobs'
];

const sectionType = parsedData.section_type || '';
if (!validSections.includes(sectionType)) {
  throw new Error(`Invalid section_type: ${sectionType}. Must be one of: ${validSections.join(', ')}`);
}

// Determine route category
let routeCategory;
if (['approach', 'strengths', 'development', 'values'].includes(sectionType)) {
  routeCategory = 'personality';
} else if (['top_career_1', 'top_career_2', 'top_career_3'].includes(sectionType)) {
  routeCategory = sectionType;
} else if (sectionType === 'runner_ups') {
  routeCategory = 'runner_ups';
} else if (sectionType === 'outside_box') {
  routeCategory = 'outside_box';
} else if (sectionType === 'dream_jobs') {
  routeCategory = 'dream';
}

return {
  json: {
    report_id: parsedData.report_id,
    first_name: parsedData.first_name || '',
    section_type: sectionType,
    route_category: routeCategory,
    feedback: parsedData.feedback || '',
    explore: parsedData.explore || ''
  }
};

const items = $input.all();
const feedback = $('Parse Query').item.json.feedback || '';
const explore = $('Parse Query').item.json.explore || '';
const reportId = $('Parse Query').item.json.report_id;
const firstName = $('Route by Section Type').item.json.first_name || '';

// Sort by order_number if available
const sorted = items.sort((a, b) => (a.json.order_number || 0) - (b.json.order_number || 0));

const careers = sorted.map((item, i) => {
  let content = item.json.content || '';

  // Strip the "**Runner-up N: Title**\n" header from content if present
  content = content.replace(/^\*\*Runner-up \d+:\s*[^*]+\*\*\n?/, '').trim();

  return {
    id: item.json.id,
    title: item.json.title || `Runner-up ${i + 1}`,
    section_type: item.json.section_type,
    order_number: item.json.order_number,
    content: content
  };
});

return {
  json: {
    report_id: reportId,
    first_name: firstName,
    feedback: feedback,
    explore: explore,
    careers: careers
  }
};

